Refactor this nested-loop duplicate-pair finder into a single pass using a set, improving it from O(n^2) to O(n):

def has_pair_with_sum(nums, target):
    for i in range(len(nums)):
        for j in range(i + 1, len(nums)):
            if nums[i] + nums[j] == target:
                return True
    return False

reference_answer:
def has_pair_with_sum(nums, target):
    seen = set()
    for n in nums:
        if target - n in seen:
            return True
        seen.add(n)
    return False

